UPDATE jobs SET user_contributed_json = '{"way":"인적자원전문가(HR전문가)가 되려면 경영학, 인사관리학, 산업심리학, 사회학 등 관련 전공을 졸업하거나 인사·노무 관련 경력을 쌓는 것이 일반적이다.[1] 대기업·중견기업의 인사팀 신입 공채로 입사하거나, 공인노무사(CLA) 자격증을 취득하여 노무법인·인사컨설팅 회사에 취업하는 경로도 있다.[2] 글로벌 기업에서는 SHRM-CP, SPHR 등 국제 HR 인증 보유자를 우대하며, 직무분석·채용·교육훈련·평가·보상·노사관계 등 특정 분야를 전문화하는 방향이 점점 중요해지고 있다.[1] 헤드헌팅 회사나 채용 플랫폼(잡코리아, 원티드) 등에서 리크루터로 커리어를 시작하는 경로도 있다.[2]","overviewSalary":{"sal":"연봉 중위값은 약 4,000만 원이다.[1] 대기업 인사팀 과장급은 6,000만 원 이상이며, HR 컨설팅 파트너는 억대 연봉도 가능하다.[2] 공인노무사 자격 보유 시 노무법인에서 4,500만~6,000만 원대를 받는다.[1]","source":"워크넷, 커리어넷 직업백과(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 보통이상 수준을 유지할 것으로 전망된다.[1] AI·빅데이터 기반 HR 테크(채용 자동화, 성과 분석 시스템)의 도입으로 단순 업무는 줄지만, 전략적 인재 관리와 조직문화 설계 역할의 수요는 오히려 증가하고 있다.[2] ESG 경영 확산과 다양성·포용성(D&I) 이슈로 HR 전문성에 대한 조직의 요구가 높아지는 추세다.[1]","source":"커리어넷 직업백과, 한국HR협회(2024)"},"trivia":"HR이라는 용어는 1960년대 미국에서 ''직원''을 단순 노동력이 아닌 ''인적 자원''으로 바라보는 시각의 전환에서 탄생했다.[1] 구글은 채용 과정에서 구조화 면접(structured interview)을 도입하여 면접관의 주관적 편견을 최소화하는 HR 혁신으로 유명하다.[2] 넷플릭스는 ''자유와 책임(Freedom & Responsibility)'' 문화를 HR 철학의 핵심으로 삼아, 휴가 일수를 없애고 성과로만 평가하는 방식을 채택했다.[3] 한국에서는 1997년 IMF 외환위기 이후 연공서열 중심의 인사 제도가 성과주의 제도로 급격히 전환되면서 HR 전문가 수요가 크게 늘었다.[1]","detailWlb":{"wlb":"보통이상","social":"보통이상","wlbDetail":"공채 시즌(상·하반기)이나 조직 개편 시기에는 야근이 집중되지만, 평상시에는 일반 사무직 대비 워라밸이 양호한 편이다. HR 부서는 임직원의 복지를 직접 설계하는 만큼 자신이 만든 제도의 혜택도 누리는 경향이 있다.","socialDetail":"조직 구성원의 채용, 교육, 성장, 보상, 퇴직까지 전 생애주기를 관리하는 역할로 사내 신뢰도가 높다. 노사 분쟁 예방, 조직문화 개선 등을 통해 사회 전반의 노동 환경 개선에도 기여한다."},"detailReady":{"curriculum":["경영학과, 인사관리학과, 산업심리학과 등 관련 전공 입학","공인노무사(CLA) 자격시험 준비: 노동법, 민법, 사회보험법 등","HR 관련 인턴십: 대기업 인사팀, 리쿠르팅 에이전시, 헤드헌팅 회사","Excel·HRIS 시스템(SAP HR, 더존) 활용 능력 및 인사 분석(People Analytics) 기초 학습"],"recruit":["대기업·중견기업 인사팀 신입 공채","공인노무사 자격 취득 후 노무법인 취업","채용 대행 전문 기업(에이치알피플, 커리어케어 등) 취업","HR 테크 스타트업 또는 HRD 컨설팅 회사 취업"],"training":["공인노무사 자격 취득 후 전문 노무법인 개업","SHRM-CP(Society for Human Resource Management) 국제 자격 취득","CHO(최고인사책임자) 또는 HR 이사로 관리직 성장","HR 컨설팅 회사 파트너급으로 독립 컨설팅"]},"sidebarJobs":["노무사","헤드헌터","직업상담사","경영컨설턴트","비서"],"sidebarMajors":["경영학과","심리학과","사회학과","행정학과","법학과"],"sidebarCerts":["공인노무사","SHRM-CP","직업상담사","사회조사분석사","HRD전문가"],"heroTags":["HR전문가","인사관리","채용전문가","HRD","공인노무사"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=220"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=220"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=220"},{"id":2,"text":"한국HR협회","url":"https://www.koreahra.or.kr/"}],"trivia":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=220"},{"id":2,"text":"구글 리크루팅 방법론","url":"https://rework.withgoogle.com/"},{"id":3,"text":"넷플릭스 컬처덱","url":"https://jobs.netflix.com/culture"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=220"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=220"}]}}' WHERE id = '1765283413781188';

UPDATE jobs SET user_contributed_json = '{"way":"비서가 되려면 비서학과, 비서행정학과, 경영학과 등을 졸업하거나 비서 전문 교육기관에서 교육을 이수하는 것이 유리하다.[1] 한국비서협회 시행 비서 1급·2급 자격증을 취득하면 취업에 도움이 되며, 외국어(영어·중국어·일본어 등) 능력이 특히 중요하다.[2] 대기업·외국계 기업의 경우 공채나 수시 채용을 통해 임원 비서로 입사하며, 중소기업은 총무팀 겸직 형태로 비서 업무를 담당하는 경우가 많다.[1] 초기에는 일반 비서로 시작하여 경력이 쌓이면 사장 비서실, 또는 경영 지원팀 관리직으로 성장하는 경로도 있다.[2]","overviewSalary":{"sal":"연봉 중위값은 약 3,200만 원이다.[1] 대기업 CEO 비서는 4,500만~6,000만 원, 외국계 기업 임원 비서는 5,000만 원 이상도 가능하다.[2] 외국어 능통자와 경력 5년 이상의 경우 연봉 협상력이 높다.[1]","source":"워크넷, 한국비서협회(2024)"},"overviewProspect":{"main":"향후 5년간 고용은 다소 감소할 것으로 전망된다.[1] AI 비서 프로그램(ChatGPT, Copilot 등)의 발전으로 일정 관리·문서 작성 등 단순 업무 자동화가 진행되고 있다.[2] 그러나 고위 임원 비서의 경우 기밀 관리, 대인 관계, 위기 대응 등 인적 역량이 필수여서 완전 대체는 어렵다는 평가다.[1]","source":"커리어넷 직업백과(2024)"},"trivia":"비서(秘書)라는 한자어는 ''비밀 문서를 관리하는 사람''이라는 뜻으로, 고대 중국 황실에서 기원했다.[1] 미국에서 가장 유명한 비서 중 한 명은 조지 C. 마샬의 비서였던 에블린 우드로, 그는 주요 외교 문서의 기밀을 40년 이상 지켜냈다.[2] 영어 ''Secretary''는 라틴어 ''secretarius(비밀을 아는 자)''에서 유래했으며, 현재도 장관(Secretary of State)이나 총무(General Secretary)처럼 고위 직책에 쓰인다.[3] 일부 임원 비서는 보스의 건강 관리·식사 주문·자녀 스케줄까지 통합 관리하는 ''퍼스널 어시스턴트(PA)'' 역할을 겸한다.[1]","detailWlb":{"wlb":"보통이하","social":"보통","wlbDetail":"임원의 일정에 맞춰 출퇴근 시간이 결정되므로 본인의 퇴근 시간을 스스로 정할 수 없는 경우가 많다. 해외 출장 동행, 야간·주말 긴급 요청 대응 등으로 개인 시간 확보가 어렵다. 특히 대기업 CEO 비서는 24시간 언제든 연락에 응해야 하는 상시 대기 상태에 가깝다.","socialDetail":"조직의 핵심 의사결정자를 지원하여 비즈니스 흐름의 润滑油(윤활유) 역할을 한다. 기밀 유지, 신뢰 관계, 전문 서비스 제공으로 조직 운영에 없어서는 안 될 존재지만 표면적으로 드러나지 않는 직업이다."},"detailReady":{"curriculum":["비서학과, 비서행정학과, 경영학과 등 관련 전공 입학","비서 자격증(1급·2급) 준비: 한국비서협회 시행","영어·중국어·일본어 등 외국어 능력 강화 (TOEIC 800점 이상 권장)","비즈니스 매너, 프로토콜, 프레젠테이션 스킬 교육 이수"],"recruit":["대기업·공기업 임원 비서 공채 및 수시 채용","외국계 기업 Executive Assistant 채용","헤드헌팅 회사 통한 비서 경력직 이직","중소기업 경영지원팀·총무팀 비서 겸직 채용"],"training":["CEO 비서실장 또는 경영지원팀 팀장으로 관리직 성장","이벤트 플래너, 프로토콜 전문가로 전문화","기업 커뮤니케이션팀 또는 대외협력팀 이동","독립 프리랜서 PA(Personal Assistant)로 고소득 전문직 전환"]},"sidebarJobs":["인적자원전문가","경영컨설턴트","헤드헌터","여행사무원","조세행정사무원"],"sidebarMajors":["비서학과","비서행정학과","경영학과","행정학과"],"sidebarCerts":["비서1급","비서2급","TOEIC 800+","컴퓨터활용능력","MOS(Office 자격)"],"heroTags":["비서","임원비서","경영지원","PA","비서자격증"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=185"},{"id":2,"text":"한국비서협회","url":"https://www.ksa.or.kr/"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보","url":"https://www.work.go.kr/empinfo/occInfoSrch/occInfoMain.do"},{"id":2,"text":"한국비서협회","url":"https://www.ksa.or.kr/"}],"overviewProspect.main":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=185"},{"id":2,"text":"고용노동부 직업전망","url":"https://www.moel.go.kr/"}],"trivia":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=185"},{"id":2,"text":"세계비서연맹(IAAP)","url":"https://www.iaap-hq.org/"},{"id":3,"text":"어원사전(Etymology Online)","url":"https://www.etymonline.com/word/secretary"}],"detailWlb.wlbDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=185"}],"detailWlb.socialDetail":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=185"}]}}' WHERE id = '1765283425058548';